// For each slug, find its guide block and insert 'en:' locale before the closing '    },'
// Strategy: find the fi: locale block end and insert en: after it, before the locales closing
let updatedCount = 0;

for (const [slug, enLocale] of Object.entries(enLocales)) {
  // Find the position of this slug in the content
  const slugStr = `slug: "${slug}"`;
  const slugIdx = content.indexOf(slugStr);
  if (slugIdx === -1) {
    console.log(`WARNING: slug not found: ${slug}`);
    continue;
  }

  // Check if already has en: locale in this block
  // Find the next slug position (or end of array)
  const nextSlugIdx = content.indexOf('\n  {', slugIdx + 10);
  const blockEnd = nextSlugIdx === -1 ? content.length : nextSlugIdx;
  const block = content.slice(slugIdx, blockEnd);

  if (block.includes('en:')) {
    console.log(`SKIP (already has en): ${slug}`);
    continue;
  }

  // Find 'fi:' in this block, then find the end of fi locale
  // The fi locale ends either with '},\n' followed by spaces+'},' (closing locales)
  // or with '    },' (multi-line format)
  // Look for the pattern: fi: { ... } followed by closing of locales object

  // Find fi: in this block
  const fiRelIdx = block.indexOf('\n      fi:');
  if (fiRelIdx === -1) {
    console.log(`WARNING: no fi: in block for: ${slug}`);
    continue;
  }

  const fiAbsIdx = slugIdx + fiRelIdx;

  // Find where fi block ends - look for the pattern that closes fi and then locales
  // For inline format: fi: { ... },\n    },\n  },  (or similar)
  // For multi-line: fi: {\n        ...\n      },\n    },\n  },

  // Find end of fi block - the '},' that closes fi locale
  // After fi: { we need to find the matching closing }
  const fiStart = content.indexOf('fi:', fiAbsIdx) + 3;

  // Find the closing of the fi object - looking for: fi: { ... },
  // We'll find the next '      },' or inline '},\n    },'

  // Simple approach: find the last '},' before '    },' in this block from fi position
  // For inline format, fi ends with: fi: { ... },
  // Then next line is likely '    },' closing locales

  // Let's look for the pattern after fi:
  // In inline: "fi: { ... }," followed by newline+spaces+"}"
  // In multi-line: similar but spread across lines

  // Find '    },' after fi position in block (relative to block start)
  const fromFi = fiAbsIdx - slugIdx;

  // Find the closing brace pattern after fi
  // Look for '},\n    },' pattern (inline fi followed by locales close)
  // or '      },\n    },' (multi-line fi)

  let insertPos = -1;

  // Try inline pattern first: '},\n    },'
  const inlinePattern = '},\n    },\n  },';
  const inlineIdx = block.indexOf(inlinePattern, fromFi);
  if (inlineIdx !== -1) {
    // Insert after the fi '}'  i.e., before '\n    },\n  },'
    insertPos = slugIdx + inlineIdx + 2; // after '},' of fi
    const insertion = '\n' + enLocale;
    content = content.slice(0, insertPos) + insertion + content.slice(insertPos);
    updatedCount++;
    console.log(`Updated (inline): ${slug}`);
    continue;
  }

  // Try multi-line pattern: '},\n    },'  but with different spacing
  // Look for '      },\n    },'
  const multiPattern = '      },\n    },\n  },';
  const multiIdx = block.indexOf(multiPattern, fromFi);
  if (multiIdx !== -1) {
    insertPos = slugIdx + multiIdx + 8; // after '      },'
    const insertion = '\n' + enLocale;
    content = content.slice(0, insertPos) + insertion + content.slice(insertPos);
    updatedCount++;
    console.log(`Updated (multi): ${slug}`);
    continue;
  }

  // Try end-of-array pattern (last guide): '},\n    },\n  }\n];'
  const endPattern = '},\n    },\n  }\n];';
  const endIdx = block.indexOf(endPattern, fromFi);
  if (endIdx !== -1) {
    insertPos = slugIdx + endIdx + 2;
    const insertion = '\n' + enLocale;
    content = content.slice(0, insertPos) + insertion + content.slice(insertPos);
    updatedCount++;
    console.log(`Updated (end): ${slug}`);
    continue;
  }

  console.log(`WARNING: could not find insertion point for: ${slug}`);
  // Debug: show the relevant portion of the block
  const blockSlice = block.slice(fromFi, fromFi + 200);
  console.log('Block slice:', JSON.stringify(blockSlice));
}

console.log(`\nTotal updated: ${updatedCount}`);
fs.writeFileSync(filePath, content, 'utf8');
console.log('File written successfully.');
